		await flush();
		await act(async () => {
			gate.resolve();
		});
		await tick(1000);

		act(() => {
			advance?.("a stray callback from a leaked request");
		});

		expect(result.current.phase).toBe("sent");
		expect(result.current.percent).toBe(100);
		expect(result.current.stage).not.toBe(
			"a stray callback from a leaked request",
